// MARK: - Deep Link Navigator

class DeepLinkNavigator {
    
    static let shared = DeepLinkNavigator()
    
    private init() {}
    
    private var pendingRoute: DeepLinkRoute?
    
    func handleRoute(_ route: DeepLinkRoute) {
        guard let rootViewController = UIApplication.shared.connectedScenes
            .compactMap({ $0 as? UIWindowScene })
            .flatMap({ $0.windows })
            .first(where: { $0.isKeyWindow })?.rootViewController else {
            pendingRoute = route
            return
        }
        
        navigate(to: route, from: rootViewController)
    }
    
    func handlePendingRouteIfNeeded() {
        guard let route = pendingRoute else { return }
        pendingRoute = nil
        handleRoute(route)
    }
    
    private func navigate(to route: DeepLinkRoute, from rootViewController: UIViewController) {
        let navigationController = findNavigationController(from: rootViewController)
        
        // Dismiss any presented view controllers first
        if let presented = rootViewController.presentedViewController {
            presented.dismiss(animated: false) { [weak self] in
                self?.pushViewController(for: route, onto: navigationController ?? rootViewController)
            }
        } else {
            pushViewController(for: route, onto: navigationController ?? rootViewController)
        }
    }
    
    private func pushViewController(for route: DeepLinkRoute, onto controller: UIViewController) {
        let destinationVC = createViewController(for: route)
        
        guard let destinationVC = destinationVC else {
            print("DeepLinkNavigator: Unknown route, cannot navigate.")
            showAlert(on: controller, title: "Invalid Link", message: "Sorry, we couldn't process that link.")
            return
        }
        
        if let navController = controller as? UINavigationController {
            navController.pushViewController(destinationVC, animated: true)
        } else if let navController = controller.navigationController {
            navController.pushViewController(destinationVC, animated: true)
        } else {
            let navController = UINavigationController(rootViewController: destinationVC)
            navController.modalPresentationStyle = .fullScreen
            controller.present(navController, animated: true)
        }
    }
    
    private func createViewController(for route: DeepLinkRoute) -> UIViewController? {
        switch route {
        case .profile(let userID):
            let vc = ProfileViewController()
            vc.userID = userID
            return vc
            
        case .paymentConfirm(let transactionID):
            let vc = PaymentConfirmViewController()
            vc.transactionID = transactionID
            return vc
            
        case .adminSettings:
            // Check for admin authorization before navigating
            guard isUserAdmin() else {
                print("DeepLinkNavigator: User is not authorized for admin settings.")
                return nil
            }
            let vc = AdminSettingsViewController()
            return vc
            
        case .unknown:
            return nil
        }
    }
    
    private func isUserAdmin() -> Bool {
        // Replace with actual admin check logic
        // e.g., check UserDefaults, Keychain, or a user session manager
        return true
    }
    
    private func findNavigationController(from viewController: UIViewController) -> UINavigationController? {
        if let navController = viewController as? UINavigationController {
            return navController
        }
        if let tabBarController = viewController as? UITabBarController,
           let selectedVC = tabBarController.selectedViewController {
            return findNavigationController(from: selectedVC)
        }
        if let navController = viewController.navigationController {
            return navController
        }
        for child in viewController.children {
            if let navController = findNavigationController(from: child) {
                return navController
            }
        }
        return nil
    }
    
    private func showAlert(on controller: UIViewController, title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        
        let presenter: UIViewController
        if let navController = controller as? UINavigationController,
           let topVC = navController.topViewController {
            presenter = topVC
        } else {
            presenter = controller
        }
        presenter.present(alert, animated: true)
    }
}

// MARK: - Universal Link Analytics Tracker

class DeepLinkAnalytics {
    
    static let shared = DeepLinkAnalytics()
    
    private init() {}
    
    func trackDeepLink(url: URL, route: DeepLinkRoute, source: DeepLinkSource) {
        let queryItems = URLComponents(url: url, resolvingAgainstBaseURL: true)?.queryItems ?? []
        
        let campaignID = queryItems.first(where: { $0.name == "utm_campaign" })?.value
        let sourceParam = queryItems.first(where: { $0.name == "utm_source" })?.value
        let medium = queryItems.first(where: { $0.name == "utm_medium" })?.value
        
        let event: [String: Any] = [
            "url": url.absoluteString,
            "route": route.description,
            "source": source.rawValue,
            "campaign_id": campaignID ?? "none",
            "utm_source": sourceParam ?? "none",
            "utm_medium": medium ?? "none",
            "timestamp": Date().timeIntervalSince1970
        ]
        
        print("DeepLinkAnalytics: \(event)")
        // Send to your analytics backend
    }
    
    enum DeepLinkSource: String {
        case universalLink = "universal_link"
        case urlScheme = "url_scheme"
        case pushNotification = "push_notification"
        case spotlight = "spotlight"
    }
}

// MARK: - SceneDelegate with Universal Link Handling

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        let window = UIWindow(windowScene: windowScene)
        
        let homeVC = UIViewController()
        homeVC.view.backgroundColor = .systemBackground
        homeVC.title = "Home"
        
        let label = UILabel()
        label.text = "Home Screen\n\nWaiting for deep links..."
        label.numberOfLines = 0
        label.textAlignment = .center
        label.font = UIFont.systemFont(ofSize: 20, weight: .medium)
        label.translatesAutoresizingMaskIntoConstraints = false
        homeVC.view.addSubview(label)
        NSLayoutConstraint.activate([
            label.centerXAnchor.constraint(equalTo: homeVC.view.centerXAnchor),
            label.centerYAnchor.constraint(equalTo: homeVC.view.centerYAnchor),
            label.leadingAnchor.constraint(equalTo: homeVC.view.leadingAnchor, constant: 20),
            label.trailingAnchor.constraint(equalTo: homeVC.view.trailingAnchor, constant: -20)
        ])
        
        let navigationController = UINavigationController(rootViewController: homeVC)
        window.rootViewController = navigationController
        window.makeKeyAndVisible()
        self.window = window
        
        // Handle universal link if app was launched from one
        if let userActivity = connectionOptions.userActivities.first(where: {
            $0.activityType == NSUserActivityTypeBrowsingWeb
        }) {
            handleUserActivity(userActivity)
        }
        
        // Handle URL contexts (URL scheme)
        if let urlContext = connectionOptions.urlContexts.first {
            handleURL(urlContext.url, source: .urlScheme)
        }
        
        // Process any pending deep link
        DeepLinkNavigator.shared.handlePendingRouteIfNeeded()
    }
    
    // Called when the app is already running and a universal link is opened
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        handleUserActivity(userActivity)
    }
    
    // Called when a URL scheme link is opened while app is running
    func scene(_ scene: UIScene, openURLContexts URLContexts: Set<UIOpenURLContext>) {
        guard let url = URLContexts.first?.url else { return }
        handleURL(url, source: .urlScheme)
    }
    
    // MARK: - Private Helpers
    
    private func handleUserActivity(_ userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        handleURL(url, source: .universalLink)
    }
    
    private func handleURL(_ url: URL, source: DeepLinkAnalytics.DeepLinkSource) {
        let route = DeepLinkParser.parse(url: url)
        
        // Track analytics
        DeepLinkAnalytics.shared.trackDeepLink(url: url, route: route, source: source)
        
        // Navigate
        DeepLinkNavigator.shared.handleRoute(route)
    }
}

